CREATE SCHEMA IF NOT EXISTS workbench;

CREATE OR REPLACE FUNCTION workbench.ack_resolved(p_module text)
 RETURNS TABLE(id integer, to_module text, msg_type text, subject text, resolution text)
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  UPDATE workbench.agent_message
    SET acknowledged_at = resolved_at
    WHERE from_module = p_module
      AND status = 'resolved'
      AND (acknowledged_at IS NULL OR resolved_at > acknowledged_at)
    RETURNING agent_message.id, agent_message.to_module, agent_message.msg_type,
              agent_message.subject, agent_message.resolution;
$function$;
COMMENT ON FUNCTION workbench.ack_resolved(text) IS 'Auto-acknowledge resolved sent messages — used by Stop hook';

CREATE OR REPLACE FUNCTION workbench.agent_message_create(p_row workbench.agent_message)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row jsonb;
BEGIN
  INSERT INTO workbench.agent_message (from_module, to_module, msg_type, subject, body, priority, reply_to, payload)
  VALUES (p_row.from_module, p_row.to_module, p_row.msg_type, p_row.subject, p_row.body,
          coalesce(p_row.priority, 'normal'), p_row.reply_to, p_row.payload)
  RETURNING to_jsonb(agent_message.*) INTO v_row;

  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION workbench.agent_message_create(workbench.agent_message) IS 'Create a new agent message';

CREATE OR REPLACE FUNCTION workbench.agent_message_delete(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row jsonb;
BEGIN
  DELETE FROM workbench.agent_message
  WHERE id = p_id::integer
  RETURNING to_jsonb(agent_message.*) INTO v_row;

  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION workbench.agent_message_delete(text) IS 'Delete an agent message by id';

CREATE OR REPLACE FUNCTION workbench.agent_message_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  IF p_filter IS NULL THEN
    RETURN QUERY
      SELECT to_jsonb(m) || jsonb_build_object(
        'issue_id', ir.id,
        'issue_type', ir.issue_type
      )
      FROM workbench.agent_message m
      LEFT JOIN workbench.issue_report ir ON ir.message_id = m.id
      ORDER BY m.id DESC;
  ELSE
    RETURN QUERY EXECUTE
      'SELECT to_jsonb(m) || jsonb_build_object(
        ''issue_id'', ir.id,
        ''issue_type'', ir.issue_type
      )
      FROM workbench.agent_message m
      LEFT JOIN workbench.issue_report ir ON ir.message_id = m.id
      WHERE ' || pgv.rsql_to_where(p_filter, 'workbench', 'agent_message')
      || ' ORDER BY m.id DESC';
  END IF;
END;
$function$;
COMMENT ON FUNCTION workbench.agent_message_list(text) IS 'List messages with resolved issue link — optional RSQL filter';

CREATE OR REPLACE FUNCTION workbench.agent_message_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  v_row    jsonb;
  v_status text;
  v_actions jsonb := '[]'::jsonb;
  v_reply_count integer;
BEGIN
  SELECT to_jsonb(m) || jsonb_build_object(
    'issue_id', ir.id,
    'issue_type', ir.issue_type,
    'issue_status', ir.status
  )
  INTO v_row
  FROM workbench.agent_message m
  LEFT JOIN workbench.issue_report ir ON ir.message_id = m.id
  WHERE m.id = p_id::integer;

  IF v_row IS NULL THEN RETURN NULL; END IF;

  -- Stats
  SELECT count(*) INTO v_reply_count
  FROM workbench.agent_message
  WHERE reply_to = p_id::integer;

  v_row := v_row || jsonb_build_object('reply_count', v_reply_count);

  -- HATEOAS actions based on state
  v_status := v_row->>'status';
  CASE v_status
    WHEN 'new' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'acknowledge', 'uri', 'workbench://agent_message/' || p_id || '/acknowledge'),
        jsonb_build_object('method', 'resolve', 'uri', 'workbench://agent_message/' || p_id || '/resolve'),
        jsonb_build_object('method', 'delete', 'uri', 'workbench://agent_message/' || p_id || '/delete')
      );
    WHEN 'acknowledged' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'resolve', 'uri', 'workbench://agent_message/' || p_id || '/resolve'),
        jsonb_build_object('method', 'delete', 'uri', 'workbench://agent_message/' || p_id || '/delete')
      );
    WHEN 'resolved' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'delete', 'uri', 'workbench://agent_message/' || p_id || '/delete')
      );
    ELSE
      v_actions := '[]'::jsonb;
  END CASE;

  RETURN v_row || jsonb_build_object('actions', v_actions);
END;
$function$;
COMMENT ON FUNCTION workbench.agent_message_read(text) IS 'Read message by id with enriched FK fields, stats, and HATEOAS actions';

CREATE OR REPLACE FUNCTION workbench.agent_message_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_msg record;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading('Messages'),
        pgv.ui_table('messages', jsonb_build_array(
          pgv.ui_col('id', '#', pgv.ui_link('#{id}', '/workbench/agent_message/{id}')),
          pgv.ui_col('from_module', 'De'),
          pgv.ui_col('to_module', 'A'),
          pgv.ui_col('msg_type', 'Type', pgv.ui_badge('{msg_type}')),
          pgv.ui_col('priority', 'Priorité', pgv.ui_badge('{priority}')),
          pgv.ui_col('subject', 'Sujet'),
          pgv.ui_col('issue_id', 'Issue', pgv.ui_link('#{issue_id}', '/workbench/issue_report/{issue_id}')),
          pgv.ui_col('status', 'Statut', pgv.ui_badge('{status}'))
        ))
      ),
      'datasources', jsonb_build_object(
        'messages', pgv.ui_datasource('workbench://agent_message', 20, true, '-id')
      )
    );
  END IF;

  -- Detail mode
  SELECT m.*, ir.id AS issue_id, ir.issue_type, ir.status AS issue_status, ir.description AS issue_description
  INTO v_msg
  FROM workbench.agent_message m
  LEFT JOIN workbench.issue_report ir ON ir.message_id = m.id
  WHERE m.id = p_slug::integer;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      pgv.ui_row(
        pgv.ui_link('← Messages', '/workbench/messages'),
        pgv.ui_heading('Message #' || v_msg.id)
      ),

      pgv.ui_heading('Informations', 3),
      pgv.ui_row(
        pgv.ui_badge(v_msg.msg_type),
        pgv.ui_badge(v_msg.status),
        pgv.ui_badge(v_msg.priority)
      ),
      pgv.ui_row(
        pgv.ui_text('De: ' || v_msg.from_module),
        pgv.ui_text('A: ' || v_msg.to_module)
      ),
      pgv.ui_text(v_msg.subject),

      pgv.ui_heading('Corps', 3),
      pgv.ui_text(coalesce(v_msg.body, '')),

      CASE WHEN v_msg.resolution IS NOT NULL THEN
        pgv.ui_column(
          pgv.ui_heading('Résolution', 3),
          pgv.ui_text(v_msg.resolution)
        )
      ELSE '{"type":"text","value":""}'::jsonb
      END,

      CASE WHEN v_msg.issue_id IS NOT NULL THEN
        pgv.ui_column(
          pgv.ui_heading('Issue liée', 3),
          pgv.ui_row(
            pgv.ui_link('#' || v_msg.issue_id || ' — ' || coalesce(v_msg.issue_description, ''), '/workbench/issue_report/' || v_msg.issue_id),
            pgv.ui_badge(coalesce(v_msg.issue_status, ''))
          )
        )
      ELSE '{"type":"text","value":""}'::jsonb
      END
    )
  );
END;
$function$;
COMMENT ON FUNCTION workbench.agent_message_ui(text) IS 'SDUI view: message list + detail with type, priority, linked issue';

CREATE OR REPLACE FUNCTION workbench.agent_message_update(p_row workbench.agent_message)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row jsonb;
BEGIN
  UPDATE workbench.agent_message SET
    status      = coalesce(p_row.status, status),
    resolution  = coalesce(p_row.resolution, resolution),
    result      = coalesce(p_row.result, result),
    resolved_at = CASE WHEN p_row.status = 'resolved' THEN now() ELSE resolved_at END,
    acknowledged_at = CASE WHEN p_row.status = 'acknowledged' AND acknowledged_at IS NULL THEN now() ELSE acknowledged_at END
  WHERE id = p_row.id
  RETURNING to_jsonb(agent_message.*) INTO v_row;

  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION workbench.agent_message_update(workbench.agent_message) IS 'Update an agent message (status, resolution, result)';

