 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  IF p_filter IS NULL THEN
    RETURN QUERY
      SELECT to_jsonb(i) || jsonb_build_object(
        'message_subject', m.subject
      )
      FROM workbench.issue_report i
      LEFT JOIN workbench.agent_message m ON m.id = i.message_id
      ORDER BY i.id DESC;
  ELSE
    RETURN QUERY EXECUTE
      'SELECT to_jsonb(i) || jsonb_build_object(
        ''message_subject'', m.subject
      )
      FROM workbench.issue_report i
      LEFT JOIN workbench.agent_message m ON m.id = i.message_id
      WHERE ' || pgv.rsql_to_where(p_filter, 'workbench', 'issue_report')
      || ' ORDER BY i.id DESC';
  END IF;
END;
$function$;
COMMENT ON FUNCTION workbench.issue_report_list(text) IS 'List issues with resolved message subject — optional RSQL filter';

CREATE OR REPLACE FUNCTION workbench.issue_report_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  v_row    jsonb;
  v_status text;
  v_actions jsonb := '[]'::jsonb;
  v_related_count integer;
BEGIN
  SELECT to_jsonb(i) || jsonb_build_object(
    'message_subject', m.subject,
    'message_from', m.from_module,
    'message_status', m.status
  )
  INTO v_row
  FROM workbench.issue_report i
  LEFT JOIN workbench.agent_message m ON m.id = i.message_id
  WHERE i.id = p_id::integer;

  IF v_row IS NULL THEN RETURN NULL; END IF;

  -- Stats
  SELECT count(*) INTO v_related_count
  FROM workbench.agent_message
  WHERE (payload->>'issue_id')::integer = p_id::integer;

  v_row := v_row || jsonb_build_object('related_message_count', v_related_count);

  -- HATEOAS actions based on state
  v_status := v_row->>'status';
  CASE v_status
    WHEN 'open' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'acknowledge', 'uri', 'workbench://issue_report/' || p_id || '/acknowledge'),
        jsonb_build_object('method', 'close', 'uri', 'workbench://issue_report/' || p_id || '/close'),
        jsonb_build_object('method', 'delete', 'uri', 'workbench://issue_report/' || p_id || '/delete')
      );
    WHEN 'acknowledged' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'resolve', 'uri', 'workbench://issue_report/' || p_id || '/resolve'),
        jsonb_build_object('method', 'close', 'uri', 'workbench://issue_report/' || p_id || '/close'),
        jsonb_build_object('method', 'delete', 'uri', 'workbench://issue_report/' || p_id || '/delete')
      );
    WHEN 'resolved' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'close', 'uri', 'workbench://issue_report/' || p_id || '/close'),
        jsonb_build_object('method', 'reopen', 'uri', 'workbench://issue_report/' || p_id || '/reopen'),
        jsonb_build_object('method', 'delete', 'uri', 'workbench://issue_report/' || p_id || '/delete')
      );
    WHEN 'closed' THEN
      v_actions := jsonb_build_array(
        jsonb_build_object('method', 'reopen', 'uri', 'workbench://issue_report/' || p_id || '/reopen'),
        jsonb_build_object('method', 'delete', 'uri', 'workbench://issue_report/' || p_id || '/delete')
      );
    ELSE
      v_actions := '[]'::jsonb;
  END CASE;

  RETURN v_row || jsonb_build_object('actions', v_actions);
END;
$function$;
COMMENT ON FUNCTION workbench.issue_report_read(text) IS 'Read issue by id with enriched FK fields, stats, and HATEOAS actions';

CREATE OR REPLACE FUNCTION workbench.issue_report_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_iss record;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading('Issues'),
        pgv.ui_table('issues', jsonb_build_array(
          pgv.ui_col('id', '#', pgv.ui_link('#{id}', '/workbench/issue_report/{id}')),
          pgv.ui_col('issue_type', 'Type', pgv.ui_badge('{issue_type}')),
          pgv.ui_col('module', 'Module'),
          pgv.ui_col('description', 'Description'),
          pgv.ui_col('status', 'Statut', pgv.ui_badge('{status}')),
          pgv.ui_col('message_subject', 'Message', pgv.ui_link('{message_subject}', '/workbench/agent_message/{message_id}'))
        ))
      ),
      'datasources', jsonb_build_object(
        'issues', pgv.ui_datasource('workbench://issue_report', 20, true, '-id')
      )
    );
  END IF;

  -- Detail mode
  SELECT i.*, m.subject AS message_subject, m.from_module AS message_from, m.status AS message_status
  INTO v_iss
  FROM workbench.issue_report i
  LEFT JOIN workbench.agent_message m ON m.id = i.message_id
  WHERE i.id = p_slug::integer;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      pgv.ui_row(
        pgv.ui_link('← Issues', '/workbench/issues'),
        pgv.ui_heading('Issue #' || v_iss.id)
      ),

      pgv.ui_heading('Informations', 3),
      pgv.ui_row(
        pgv.ui_badge(v_iss.issue_type),
        pgv.ui_badge(v_iss.status),
        pgv.ui_text(coalesce(v_iss.module, '-'))
      ),
      pgv.ui_text(v_iss.description),

      pgv.ui_heading('Message de dispatch', 3),
      CASE WHEN v_iss.message_id IS NOT NULL THEN
        pgv.ui_row(
          pgv.ui_link('#' || v_iss.message_id || ' — ' || coalesce(v_iss.message_subject, ''), '/workbench/agent_message/' || v_iss.message_id),
          pgv.ui_badge(coalesce(v_iss.message_status, ''))
        )
      ELSE
        pgv.ui_text('Aucun message lié')
      END
    )
  );
END;
$function$;
COMMENT ON FUNCTION workbench.issue_report_ui(text) IS 'SDUI view: issue list + detail with type, status, linked message';

CREATE OR REPLACE FUNCTION workbench.issue_report_update(p_row workbench.issue_report)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row jsonb;
BEGIN
  UPDATE workbench.issue_report SET
    issue_type  = coalesce(p_row.issue_type, issue_type),
    module      = coalesce(p_row.module, module),
    description = coalesce(p_row.description, description),
    context     = coalesce(p_row.context, context),
    status      = coalesce(p_row.status, status),
    message_id  = coalesce(p_row.message_id, message_id)
  WHERE id = p_row.id
  RETURNING to_jsonb(issue_report.*) INTO v_row;

  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION workbench.issue_report_update(workbench.issue_report) IS 'Update an issue report by id';

CREATE OR REPLACE FUNCTION workbench.issue_report_view()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_object(
    'uri', 'workbench://issue_report',
    'icon', '⚑',
    'label', 'workbench.entity_issue_report',

    'template', jsonb_build_object(
      'compact', jsonb_build_object(
        'fields', jsonb_build_array('id', 'issue_type', 'module', 'description', 'status')
      ),
      'standard', jsonb_build_object(
        'fields', jsonb_build_array('id', 'issue_type', 'module', 'description', 'status', 'created_at'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'related_message_count', 'label', 'workbench.stat_related_messages')
        ),
        'related', jsonb_build_array(
          jsonb_build_object('entity', 'workbench://agent_message', 'label', 'workbench.rel_dispatch_message', 'filter', 'id={message_id}')
        )
      ),
      'expanded', jsonb_build_object(
        'fields', jsonb_build_array('id', 'issue_type', 'module', 'description', 'context', 'status', 'created_at', 'message_id'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'related_message_count', 'label', 'workbench.stat_related_messages')
        ),
        'related', jsonb_build_array(
          jsonb_build_object('entity', 'workbench://agent_message', 'label', 'workbench.rel_dispatch_message', 'filter', 'id={message_id}'),
          jsonb_build_object('entity', 'workbench://agent_message', 'label', 'workbench.rel_related_messages', 'filter', 'payload.issue_id={id}')
        )
      ),
      'form', jsonb_build_object(
        'sections', jsonb_build_array(
          jsonb_build_object(
            'label', 'workbench.section_issue_info',
            'fields', jsonb_build_array(
              jsonb_build_object('key', 'issue_type', 'type', 'select', 'label', 'workbench.field_issue_type', 'required', true,
                'options', jsonb_build_array('bug', 'enhancement', 'question')),
              jsonb_build_object('key', 'module', 'type', 'text', 'label', 'workbench.field_module'),
              jsonb_build_object('key', 'description', 'type', 'textarea', 'label', 'workbench.field_description', 'required', true),
              jsonb_build_object('key', 'status', 'type', 'select', 'label', 'workbench.field_status',
                'options', jsonb_build_array('open', 'acknowledged', 'resolved', 'closed'))
            )
          )
        )
      )
    ),

    'actions', jsonb_build_object(
      'acknowledge', jsonb_build_object('label', 'workbench.action_acknowledge', 'icon', '✓', 'variant', 'default'),
      'resolve',     jsonb_build_object('label', 'workbench.action_resolve', 'icon', '✔', 'variant', 'primary'),
      'close',       jsonb_build_object('label', 'workbench.action_close', 'icon', '×', 'variant', 'muted'),
      'reopen',      jsonb_build_object('label', 'workbench.action_reopen', 'icon', '↺', 'variant', 'warning'),
      'delete',      jsonb_build_object('label', 'workbench.action_delete', 'icon', '🗑', 'variant', 'danger', 'confirm', 'workbench.confirm_delete_issue')
    )
  );
$function$;
COMMENT ON FUNCTION workbench.issue_report_view() IS 'SDUI _view() template for issue_report — 4 density levels + actions catalog';

CREATE OR REPLACE FUNCTION workbench.log_hook(p_module text, p_tool text, p_action text, p_allowed boolean, p_reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  INSERT INTO workbench.hook_log (module, tool, action, allowed, reason)
    VALUES (p_module, p_tool, p_action, p_allowed, p_reason);
$function$;
COMMENT ON FUNCTION workbench.log_hook(text,text,text,boolean,text) IS 'Log a hook event (fire-and-forget)';

CREATE OR REPLACE FUNCTION workbench.nav_items()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('label', pgv.t('workbench.nav_messages'), 'href', pgv.call_ref('get_messages'), 'entity', 'agent_message'),
    jsonb_build_object('label', pgv.t('workbench.nav_issues'),   'href', pgv.call_ref('get_issues'),   'entity', 'issue_report'),
    jsonb_build_object('label', pgv.t('workbench.nav_tools'),    'href', pgv.call_ref('get_tools')),
    jsonb_build_object('label', pgv.t('workbench.nav_primitives'), 'href', pgv.call_ref('get_primitives'))
  );
$function$;
COMMENT ON FUNCTION workbench.nav_items() IS 'Navigation menu items for workbench module';

CREATE OR REPLACE FUNCTION workbench.notify_channel()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM pg_notify('workbench_channel_' || NEW.to_module, json_build_object(
    'id', NEW.id,
    'from_module', NEW.from_module,
    'to_module', NEW.to_module,
    'msg_type', NEW.msg_type,
    'subject', NEW.subject,
    'priority', NEW.priority,
    'body', left(NEW.body, 500)
  )::text);
  RETURN NEW;
END;
$function$;
DROP TRIGGER IF EXISTS trg_notify_channel ON workbench.agent_message;
CREATE TRIGGER trg_notify_channel AFTER INSERT ON workbench.agent_message FOR EACH ROW EXECUTE FUNCTION workbench.notify_channel();

CREATE OR REPLACE FUNCTION workbench.on_issue_report_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_msg_id integer;
BEGIN
  INSERT INTO workbench.agent_message(from_module, to_module, msg_type, subject, body, priority, payload)
  VALUES (
    'shell',
    'lead',
    'issue_report',
    format('Issue #%s à traiter (%s)', NEW.id, NEW.issue_type),
    format('SELECT * FROM workbench.issue_report WHERE id = %s', NEW.id),
    CASE WHEN NEW.issue_type = 'bug' THEN 'high' ELSE 'normal' END,
    jsonb_build_object('issue_id', NEW.id)
  )
  RETURNING id INTO v_msg_id;

  -- Link issue to message and acknowledge
  NEW.message_id := v_msg_id;
  NEW.status := 'acknowledged';

  RETURN NEW;
END;
$function$;
COMMENT ON FUNCTION workbench.on_issue_report_insert() IS 'Trigger: crée agent_message, lie issue↔message, passe en acknowledged';
DROP TRIGGER IF EXISTS trg_issue_report_notify ON workbench.issue_report;
CREATE TRIGGER trg_issue_report_notify BEFORE INSERT ON workbench.issue_report FOR EACH ROW EXECUTE FUNCTION workbench.on_issue_report_insert();

CREATE OR REPLACE FUNCTION workbench.session_create(p_module text, p_pid integer)
 RETURNS integer
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  INSERT INTO workbench.agent_session (module, status, pid, started_at)
    VALUES (p_module, 'running', p_pid, now())
    RETURNING id;
$function$;
COMMENT ON FUNCTION workbench.session_create(text,integer) IS 'Create agent session record, return id';

CREATE OR REPLACE FUNCTION workbench.session_end(p_id integer, p_status text)
 RETURNS void
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  UPDATE workbench.agent_session
    SET status = p_status, ended_at = now()
    WHERE id = p_id;
$function$;
COMMENT ON FUNCTION workbench.session_end(integer,text) IS 'End an agent session with status';

GRANT USAGE ON SCHEMA workbench TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA workbench TO anon;
GRANT SELECT ON ALL TABLES IN SCHEMA workbench TO anon;
